import { GoogleGenAI } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are a friendly UI/UX Sales Consultant for Webtrix Innovations. 
Your goal is to answer questions about the "Basic UI/UX Website Design Package".

Details of the package:
- Price: ₹15,000 (Regular: ₹20,000)
- Deliverables: 5-7 pages of UI design in Figma.
- Features: Custom homepage, Mobile responsive, Design system, Wireframes, Figma source file, 1 Revision.
- Delivery: 5-7 working days.
- Exclusions: No development, no coding, no hosting.
- Company: Webtrix Innovations.
- Contact: +919209767989 or webtrixinnovations.com.

Be professional, helpful, and concise. Always try to guide the user toward booking the package or contacting via WhatsApp.
`;

export const getAIResponse = async (userMessage: string) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-latest',
      contents: userMessage,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
      },
    });
    return response.text || "I'm sorry, I couldn't process that. Please contact our human experts via WhatsApp!";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Something went wrong. Please chat with us on WhatsApp for faster assistance!";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { X, Send, User, Bot, Loader2, MessageSquare } from 'lucide-react';
import { getAIResponse } from '../services/gemini';

interface Message {
  role: 'user' | 'bot';
  text: string;
}

interface AIConsultantProps {
  isOpen: boolean;
  onClose: () => void;
}

const AIConsultant: React.FC<AIConsultantProps> = ({ isOpen, onClose }) => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'bot', text: 'Hi! I\'m your Webtrix Design Assistant. How can I help you with our UI/UX package today?' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    const response = await getAIResponse(userMsg);
    setMessages(prev => [...prev, { role: 'bot', text: response }]);
    setIsLoading(false);
  };

  if (!isOpen) return (
    <button 
      onClick={() => onClose()} // This is used to toggle opening from the App state
      className="fixed bottom-6 right-6 w-14 h-14 bg-blue-600 rounded-full shadow-2xl flex items-center justify-center text-white hover:scale-110 transition-transform z-50 cursor-pointer"
      title="Ask AI Assistant"
    >
      <MessageSquare className="w-6 h-6" />
    </button>
  );

  return (
    <div className="fixed bottom-0 right-0 sm:bottom-6 sm:right-6 w-full sm:w-[400px] h-full sm:h-[600px] bg-white sm:rounded-3xl shadow-2xl flex flex-col z-[100] border border-slate-200 overflow-hidden">
      <div className="bg-blue-600 p-6 flex justify-between items-center text-white">
        <div>
          <h3 className="font-bold text-lg">Webtrix AI Assistant</h3>
          <p className="text-xs text-blue-100">Usually replies instantly</p>
        </div>
        <button onClick={onClose} className="p-2 hover:bg-blue-500 rounded-full transition-colors">
          <X className="w-6 h-6" />
        </button>
      </div>

      <div ref={scrollRef} className="flex-grow overflow-y-auto p-6 space-y-4 bg-slate-50">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex gap-3 max-w-[85%] ${m.role === 'user' ? 'flex-row-reverse' : ''}`}>
              <div className={`w-8 h-8 rounded-full flex-shrink-0 flex items-center justify-center ${m.role === 'user' ? 'bg-blue-100 text-blue-600' : 'bg-white border border-slate-200 text-slate-400'}`}>
                {m.role === 'user' ? <User className="w-4 h-4" /> : <Bot className="w-4 h-4" />}
              </div>
              <div className={`p-4 rounded-2xl text-sm leading-relaxed ${m.role === 'user' ? 'bg-blue-600 text-white shadow-lg' : 'bg-white text-slate-700 shadow-sm border border-slate-100'}`}>
                {m.text}
              </div>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="flex gap-3 max-w-[85%]">
              <div className="w-8 h-8 rounded-full bg-white border border-slate-200 flex items-center justify-center text-slate-400">
                <Bot className="w-4 h-4" />
              </div>
              <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100">
                <Loader2 className="w-5 h-5 animate-spin text-blue-500" />
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t border-slate-100">
        <div className="flex gap-2 bg-slate-100 p-2 rounded-2xl">
          <input 
            type="text" 
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder="Ask about our UI/UX package..."
            className="flex-grow bg-transparent border-none focus:ring-0 text-sm px-4 py-2"
          />
          <button 
            onClick={handleSend}
            disabled={isLoading}
            className="p-2 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition-colors disabled:opacity-50"
          >
            <Send className="w-5 h-5" />
          </button>
        </div>
        <p className="text-[10px] text-center text-slate-400 mt-2">
          Powered by Gemini AI • Always verify crucial details with our team.
        </p>
      </div>
    </div>
  );
};

export default AIConsultant;

